import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.provider.Settings;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Switch;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;

import java.util.concurrent.Executor;

public class LoginActivity extends AppCompatActivity {

    private static final String TAG = "LoginActivity";
    public static final String PREFS_NAME = "BiometricAppPrefs";
    public static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";

    private SharedPreferences sharedPreferences;
    private BiometricPrompt biometricPrompt;
    private BiometricPrompt.PromptInfo promptInfo;

    private EditText usernameEditText;
    private EditText passwordEditText;
    private Button loginButton;
    private Button settingsButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        sharedPreferences = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);

        usernameEditText = findViewById(R.id.usernameEditText);
        passwordEditText = findViewById(R.id.passwordEditText);
        loginButton = findViewById(R.id.loginButton);
        settingsButton = findViewById(R.id.settingsButton);

        setupBiometricPrompt();

        boolean isBiometricEnabled = sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
        Log.d(TAG, "Biometric enabled in prefs: " + isBiometricEnabled);

        if (isBiometricEnabled) {
            authenticateWithBiometrics();
        }

        loginButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                // Simulate password login
                String username = usernameEditText.getText().toString();
                String password = passwordEditText.getText().toString();

                if ("user".equals(username) && "password".equals(password)) {
                    Toast.makeText(LoginActivity.this, "Password Login Successful", Toast.LENGTH_SHORT).show();
                    navigateToMainActivity();
                } else {
                    Toast.makeText(LoginActivity.this, "Invalid Credentials", Toast.LENGTH_SHORT).show();
                }
            }
        });

        settingsButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                Intent intent = new Intent(LoginActivity.this, SettingsActivity.class);
                startActivity(intent);
            }
        });
    }

    private void setupBiometricPrompt() {
        Executor executor = ContextCompat.getMainExecutor(this);

        biometricPrompt = new BiometricPrompt(LoginActivity.this,
                executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                super.onAuthenticationError(errorCode, errString);
                Log.e(TAG, "Authentication error: " + errString + " (Code: " + errorCode + ")");
                Toast.makeText(getApplicationContext(), "Authentication error: " + errString, Toast.LENGTH_SHORT)
                        .show();
                // Fallback to password login or inform user
                showPasswordLoginUI();
            }

            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                super.onAuthenticationSucceeded(result);
                Log.d(TAG, "Authentication succeeded!");
                Toast.makeText(getApplicationContext(), "Authentication Succeeded!", Toast.LENGTH_SHORT).show();
                navigateToMainActivity();
            }

            @Override
            public void onAuthenticationFailed() {
                super.onAuthenticationFailed();
                Log.w(TAG, "Authentication failed.");
                Toast.makeText(getApplicationContext(), "Authentication failed", Toast.LENGTH_SHORT)
                        .show();
                // User can try again or fall back to password
                showPasswordLoginUI();
            }
        });

        promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle("Biometric Login")
                .setSubtitle("Log in using your fingerprint")
                .setNegativeButtonText("Use Password")
                .build();
    }

    private void authenticateWithBiometrics() {
        BiometricManager biometricManager = BiometricManager.from(this);
        int canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);

        switch (canAuthenticate) {
            case BiometricManager.BIOMETRIC_SUCCESS:
                Log.d(TAG, "App can authenticate using biometrics.");
                biometricPrompt.authenticate(promptInfo);
                break;
            case BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE:
                Log.e(TAG, "No biometric features available on this device.");
                Toast.makeText(this, "No biometric hardware available.", Toast.LENGTH_LONG).show();
                disableBiometricInPrefs();
                showPasswordLoginUI();
                break;
            case BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE:
                Log.e(TAG, "Biometric features are currently unavailable.");
                Toast.makeText(this, "Biometric features are currently unavailable.", Toast.LENGTH_LONG).show();
                showPasswordLoginUI();
                break;
            case BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED:
                Log.e(TAG, "No biometrics enrolled. Prompting user to enroll.");
                Toast.makeText(this, "No fingerprints enrolled. Please enroll in settings.", Toast.LENGTH_LONG).show();
                // Optionally, direct user to settings to enroll biometrics
                Intent enrollIntent = new Intent(Settings.ACTION_BIOMETRIC_ENROLL);
                enrollIntent.putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                        BiometricManager.Authenticators.BIOMETRIC_STRONG | BiometricManager.Authenticators.BIOMETRIC_WEAK);
                startActivity(enrollIntent);
                disableBiometricInPrefs();
                showPasswordLoginUI();
                break;
            case BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED:
                Log.e(TAG, "Security update required for biometrics.");
                Toast.makeText(this, "Security update required for biometrics.", Toast.LENGTH_LONG).show();
                showPasswordLoginUI();
                break;
            case BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED:
                Log.e(TAG, "Biometrics unsupported for this device.");
                Toast.makeText(this, "Biometrics unsupported for this device.", Toast.LENGTH_LONG).show();
                disableBiometricInPrefs();
                showPasswordLoginUI();
                break;
            default:
                Log.e(TAG, "Unknown biometric error code: " + canAuthenticate);
                Toast.makeText(this, "Unknown biometric error.", Toast.LENGTH_LONG).show();
                showPasswordLoginUI();
                break;
        }
    }

    private void disableBiometricInPrefs() {
        sharedPreferences.edit().putBoolean(KEY_BIOMETRIC_ENABLED, false).apply();
        Log.d(TAG, "Biometric login disabled in preferences due to device incompatibility or no enrollment.");
    }

    private void showPasswordLoginUI() {
        // Make password fields visible if they were hidden
        usernameEditText.setVisibility(View.VISIBLE);
        passwordEditText.setVisibility(View.VISIBLE);
        loginButton.setVisibility(View.VISIBLE);
        // settingsButton.setVisibility(View.VISIBLE); // Keep settings button always visible
    }

    private void navigateToMainActivity() {
        Intent intent = new Intent(LoginActivity.this, MainActivity.class);
        startActivity(intent);
        finish(); // Prevent going back to login screen with back button
    }

    @Override
    protected void onResume() {
        super.onResume();
        // Re-check biometric status if returning from SettingsActivity
        boolean isBiometricEnabled = sharedPreferences.getBoolean(KEY_BIOMETRIC_ENABLED, false);
        Log.d(TAG, "onResume: Biometric enabled in prefs: " + isBiometricEnabled);
        if (isBiometricEnabled && usernameEditText.getVisibility() != View.VISIBLE) {
            // If biometric was enabled and password UI is not showing, try biometrics again
            authenticateWithBiometrics();
        } else if (!isBiometricEnabled) {
            // If biometric was disabled in settings, ensure password UI is shown
            showPasswordLoginUI();
        }
    }
}


